fn confidence_component(confidence: Option<f32>) -> f64 {
    match confidence {
        Some(c) if c.is_nan() => DEFAULT_CONFIDENCE,
        Some(c) => (c as f64).clamp(0.0, 1.0),
        None => DEFAULT_CONFIDENCE,
    }
}
fn sanitize_f64(v: f64) -> f64 {
    if v.is_nan() || v.is_infinite() {
        0.0
    } else {
        v.max(0.0)
    }
}
